INSERT INTO `evaluation_rubrics` VALUES (1,'Proposal grading scheme','Used to score and grade research proposal chapters 1–3.','[{\"name\":\"Literature Review\",\"weight\":30,\"description\":\"Quality and relevance of cited literature.\"},{\"name\":\"Methodology\",\"weight\":40,\"description\":\"Soundness of the research design and data collection methods.\"},{\"name\":\"Problem Statement\",\"weight\":20,\"description\":\"Clarity and significance of the research problem.\"},{\"name\":\"Presentation\",\"weight\":10,\"description\":\"Clarity of writing and adherence to formatting guidelines.\"}]',100,1,'2026-06-13 02:08:01','2026-06-13 02:08:01'),(2,'Final Project Scoring','Grading scheme for final research reports and system demonstrations.','[{\"name\":\"System Functionality\",\"weight\":40,\"description\":\"Completeness and correctness of the system implementation.\"},{\"name\":\"Analysis & Findings\",\"weight\":30,\"description\":\"Quality of data analysis and discussion.\"},{\"name\":\"Documentation\",\"weight\":20,\"description\":\"Quality of the final report document.\"},{\"name\":\"Innovation\",\"weight\":10,\"description\":\"Novelty and practical utility of the project.\"}]',100,1,'2026-06-13 02:08:01','2026-06-13 02:08:01');
